// User Management
package rolemanager

import (
	"context"

	"github.com/arminguenther/xeruspower-go/v40410/event/userevent"
	"github.com/arminguenther/xeruspower-go/v40410/idl"
	"github.com/arminguenther/xeruspower-go/v40410/usermgmt/role"
)

// Base type of all account event
type RoleEvent interface {
	userevent.UserEvent
	Rolename() string
	isRoleEvent()
}

type RoleAdded interface {
	RoleEvent
	isRoleAdded()
}

type RoleRemoved interface {
	RoleEvent
	isRoleRemoved()
}

type RoleChanged interface {
	RoleEvent
	OldSettings() role.Info
	NewSettings() role.Info
	isRoleChanged()
}

const (
	ERR_ROLE_ALREADY_EXISTS int32 = 1 // A role with that name already exists
	ERR_MAX_ROLES_REACHED   int32 = 2 // Maximum number of roles reached
	ERR_INVALID_VALUE       int32 = 3 // Invalid arguments
	ERR_ROLE_DOESNT_EXIST   int32 = 1 // The role does not exist
	ERR_ROLE_NOT_DELETABLE  int32 = 2 // The role cannot be deleted
)

// Role manager interface
type RoleManager interface {
	idl.Object

	// Create new role with full information.
	//
	//	@param name  New role name
	//	@param info  New role information
	//
	//	@return 0 if OK
	//	@return 1 if a role with that name already exists
	//	@return 2 if the maximum number of roles is reached
	//	@return 3 if the role information is invalid
	CreateRoleFull(ctx context.Context, name string, info role.Info) (int32, error)

	// Delete a role.
	//
	//	@param name  Name of the role to delete
	//
	//	@return 0 if OK
	//	@return 1 if a role with the given name does not exist
	//	@return 2 if the role cannot be deleted
	DeleteRole(ctx context.Context, name string) (int32, error)

	// Retrieve a list of role names
	//
	//	@return List of role names
	GetAllRoleNames(ctx context.Context) ([]string, error)

	// Retrieve a list of active roles.
	//
	//	@return List of active roles
	GetAllRoles(ctx context.Context) ([]RoleAccount, error)

	// Retrieve a list of supported privileges.
	//
	//	@return List of privilege names
	GetAllPrivileges(ctx context.Context) ([]PrivilegeDesc, error)

	// Retrieve full role manager information.
	//
	//	@return Role manager information
	GetInfo(ctx context.Context) (Info, error)
}

// Privilege Argument Description
type ArgumentDesc struct {
	Name string // Argument name
	Desc string // Argument description
}

// Privilege Description
type PrivilegeDesc struct {
	Name string         // Privilege name
	Desc string         // Privilege description
	Args []ArgumentDesc // List of supported arguments
}

// Role information
type RoleAccount struct {
	Id   int32     // Unique role id
	Name string    // Role name
	Info role.Info // Role information
}

// Full role manager information
type Info struct {
	Privileges []PrivilegeDesc // List of supported privileges
	Roles      []RoleAccount   // List of active roles
}
